'use client';

import React, { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import {  Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from '@/components/ui/select';
import {
  Mail,
  UserCheck,
  UserX,
  Edit2,
  Trash,
  Package,
  Calendar
} from 'lucide-react';

interface UserType {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'customer';
}

interface OrderType {
  id: string;
  date: string;
  total: number;
  status: 'Pending' | 'Shipped' | 'Delivered' | 'Cancelled';
}

export default function UserDetailPage() {
  const params = useParams();
  const router = useRouter();
  const userId = params?.id;

  const [user, setUser] = useState<UserType | null>(null);
  const [orders, setOrders] = useState<OrderType[]>([]);
  const [openEditDialog, setOpenEditDialog] = useState(false);
  const [editForm, setEditForm] = useState({ name: '', email: '', role: 'customer' as 'customer' | 'admin' });

  if (!userId || Array.isArray(userId)) {
    return <div className="p-6 text-red-600">Invalid user ID</div>;
  }

  useEffect(() => {
    // 🟢 Dummy user fetch
    const dummyUser: UserType = {
      id: userId,
      name: 'Priya Sharma',
      email: 'priya@example.com',
      role: 'customer',
    };
    setUser(dummyUser);
    setEditForm({ name: dummyUser.name, email: dummyUser.email, role: dummyUser.role });

    // 🟢 Dummy orders fetch
    const dummyOrders: OrderType[] = [
      { id: 'ORD-1001', date: '2025-11-01', total: 45, status: 'Delivered' },
      { id: 'ORD-1002', date: '2025-11-05', total: 90, status: 'Shipped' },
      { id: 'ORD-1003', date: '2025-11-08', total: 30, status: 'Pending' },
    ];
    setOrders(dummyOrders);

    // 🔹 Replace with API calls
    // axios.get(`/api/users/${userId}`).then(res => setUser(res.data));
    // axios.get(`/api/users/${userId}/orders`).then(res => setOrders(res.data));
  }, [userId]);

  const handleDeleteUser = () => {
    if (!user) return;
    if (!confirm('Are you sure you want to delete this user?')) return;

    // 🔹 API call
    // axios.delete(`/api/users/${user.id}`).then(() => router.push('/admin/user'));

    setUser(null);
    router.push('/admin/user');
  };

  const handleCancelOrder = (orderId: string) => {
    if (!confirm('Are you sure you want to cancel this order?')) return;

    // 🔹 API call
    // axios.put(`/api/orders/${orderId}/cancel`).then(res => fetchOrders());

    setOrders(prev =>
      prev.map(o => (o.id === orderId ? { ...o, status: 'Cancelled' } : o))
    );
  };

  const handleSaveEdit = () => {
    if (!editForm.name || !editForm.email) return alert('Fill all fields');

    // 🔹 API call
    // axios.put(`/api/users/${user.id}`, editForm).then(res => setUser(res.data));

    setUser({ ...user!, ...editForm });
    setOpenEditDialog(false);
  };

  if (!user) return <div className="p-6 text-gray-600">User not found.</div>;

  const firstOrder = orders[0];
  const lastOrder = orders[orders.length - 1];

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <h1 className="text-2xl font-bold mb-4">User Details</h1>

      {/* User Info Card */}
      <Card className="bg-white shadow hover:shadow-lg transition">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            {user.role === 'admin' ? <UserCheck size={20} /> : <UserX size={20} />} {user.name}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          <p className="flex items-center gap-2"><Mail size={16} /> {user.email}</p>
          <p className="flex items-center gap-2">Role: {user.role === 'admin' ? 'Admin' : 'Customer'}</p>

          <div className="flex flex-wrap justify-end gap-2 mt-4">
            <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white flex items-center gap-1"
              onClick={() => setOpenEditDialog(true)}>
              <Edit2 size={14} /> Edit
            </Button>
            <Button size="sm" className="bg-red-600 hover:bg-red-700 text-white flex items-center gap-1"
              onClick={handleDeleteUser}>
              <Trash size={14} /> Delete
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Orders Section */}
      <h2 className="text-xl font-semibold">Orders</h2>
      {orders.length === 0 ? (
        <p className="text-gray-600">No orders found.</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {orders.map(order => (
            <Card key={order.id} className="bg-gray-50 hover:bg-gray-100 transition">
              <CardHeader>
                <CardTitle className="flex items-center gap-2"><Package size={18} /> Order {order.id}</CardTitle>
              </CardHeader>
              <CardContent className="space-y-1">
                <p className="flex items-center gap-2"><Calendar size={14} /> Date: {order.date}</p>
                <p>Total: ₹{order.total}</p>
                <p>Status: 
                  <span className={`ml-2 px-2 py-1 rounded-full text-xs font-medium ${
                    order.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' :
                    order.status === 'Shipped' ? 'bg-blue-100 text-blue-800' :
                    order.status === 'Delivered' ? 'bg-green-100 text-green-800' :
                    'bg-red-100 text-red-800'
                  }`}>
                    {order.status}
                  </span>
                </p>

                {order.status !== 'Cancelled' && order.status !== 'Delivered' && (
                  <Button
                    size="sm"
                    className="bg-red-600 hover:bg-red-700 text-white mt-2"
                    onClick={() => handleCancelOrder(order.id)}
                  >
                    Cancel Order
                  </Button>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* First & Last Order */}
      {orders.length > 0 && (
        <div className="mt-4 grid grid-cols-1 md:grid-cols-2 gap-4">
          <Card className="bg-white shadow">
            <CardHeader><CardTitle>First Order</CardTitle></CardHeader>
            <CardContent>
              <p>ID: {firstOrder.id}</p>
              <p>Date: {firstOrder.date}</p>
              <p>Total: ₹{firstOrder.total}</p>
              <p>Status: {firstOrder.status}</p>
            </CardContent>
          </Card>
          <Card className="bg-white shadow">
            <CardHeader><CardTitle>Last Order</CardTitle></CardHeader>
            <CardContent>
              <p>ID: {lastOrder.id}</p>
              <p>Date: {lastOrder.date}</p>
              <p>Total: ₹{lastOrder.total}</p>
              <p>Status: {lastOrder.status}</p>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Edit User Dialog */}
      <Dialog open={openEditDialog} onOpenChange={setOpenEditDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Edit User</DialogTitle>
          </DialogHeader>

          <div className="space-y-3 mt-2">
            <Input
              placeholder="Name"
              value={editForm.name}
              onChange={(e) => setEditForm({ ...editForm, name: e.target.value })}
            />
            <Input
              placeholder="Email"
              value={editForm.email}
              onChange={(e) => setEditForm({ ...editForm, email: e.target.value })}
            />
            <Select
              value={editForm.role}
              onValueChange={(v) => setEditForm({ ...editForm, role: v as 'admin' | 'customer' })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select Role" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="admin">Admin</SelectItem>
                <SelectItem value="customer">Customer</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <DialogFooter className="mt-4 flex justify-end gap-2">
            <Button variant="outline" onClick={() => setOpenEditDialog(false)}>Cancel</Button>
            <Button className="bg-green-600 hover:bg-green-700 text-white" onClick={handleSaveEdit}>Save</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}



